+fn ensure_command_succeeded(run: &CapturedRun, context: &str) -> Result<(), String> {
+    if run.metrics.success {
+        return Ok(());
+    }
+
+    Err(format!(
+        "{context} failed with exit code {}: {}",
+        run.metrics.exit_code,
+        summarize_command_failure(run)
+    ))
+}
